70	func SessionIndexShardName(t time.Time) string {
71		if t.IsZero() {
72			t = time.Now().UTC()
73		}
74		return fmt.Sprintf("sessions-%04d-%02d.jsonl", t.UTC().Year(), t.UTC().Month())
75	}
