81	func ProjectIDForPath(path string) string {
82		canonical, err := filepath.Abs(path)
83		if err == nil {
84			path = canonical
85		}
86		h := sha256.Sum256([]byte(path))
87		return fmt.Sprintf("proj-%x", h[:4])
88	}
