90	func AppendSessionIndex(logDir string, entry SessionIndexEntry, now time.Time) error {
91		if logDir == "" {
92			return nil
93		}
94		if now.IsZero() {
95			now = time.Now().UTC()
96		}
97		if entry.ID == "" {
98			entry.ID = genSessionID()
99		}
100		if entry.StartedAt.IsZero() {
101			entry.StartedAt = now.UTC()
102		}
103		if entry.EndedAt.IsZero() && entry.DurationMS > 0 {
104			entry.EndedAt = entry.StartedAt.Add(time.Duration(entry.DurationMS) * time.Millisecond).UTC()
105		}
106		if entry.Outcome == "" {
107			if entry.ExitCode == 0 && entry.Detail == "" {
108				entry.Outcome = "success"
109			} else {
110				entry.Outcome = "failure"
111			}
112		}
113		if err := os.MkdirAll(SessionIndexDir(logDir), 0o755); err != nil {
114			return err
115		}
116		data, err := json.Marshal(entry)
117		if err != nil {
118			return err
119		}
120		path := SessionIndexShardPath(logDir, now.UTC())
121		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
122		if err != nil {
123			return err
124		}
125		defer f.Close()
126		_, err = fmt.Fprintf(f, "%s\n", data)
127		return err
128	}
