270	func ReadSessionIndex(logDir string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
271		files, err := SessionIndexShardFiles(logDir, q)
272		if err != nil {
273			return nil, err
274		}
275		var out []SessionIndexEntry
276		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
277			out, err = readRecentSessionIndexFiles(files, 1000)
278		} else {
279			out, err = readSessionIndexFiles(files, q)
280		}
281		if err != nil {
282			return nil, err
283		}
284		if len(out) == 0 && q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
285			files, err = SessionIndexShardFiles(logDir, SessionIndexQuery{})
286			if err != nil {
287				return nil, err
288			}
289			out, err = readSessionIndexFiles(files, q)
290			if err != nil {
291				return nil, err
292			}
293		}
294		sort.Slice(out, func(i, j int) bool {
295			return out[i].StartedAt.After(out[j].StartedAt)
296		})
297		return out, nil
298	}
299	
300	func readRecentSessionIndexFiles(files []string, perFile int) ([]SessionIndexEntry, error) {
301		var out []SessionIndexEntry
302		for _, file := range files {
303			data, err := os.ReadFile(file)
304			if os.IsNotExist(err) {
305				continue
306			}
307			if err != nil {
308				return nil, err
309			}
310			lines := bytes.Split(bytes.TrimSpace(data), []byte{'\n'})
311			start := 0
312			if perFile > 0 && len(lines) > perFile {
313				start = len(lines) - perFile
314			}
315			for _, line := range lines[start:] {
316				if len(bytes.TrimSpace(line)) == 0 {
317					continue
318				}
319				var entry SessionIndexEntry
320				if err := json.Unmarshal(line, &entry); err == nil {
321					out = append(out, entry)
322				}
323			}
324		}
325		return out, nil
326	}
