358	// PaletteSearch is the resolver for the paletteSearch field.
359	func (r *queryResolver) PaletteSearch(ctx context.Context, query string) (*PaletteSearchResults, error) {
360		q := strings.TrimSpace(query)
361		out := &PaletteSearchResults{
362			Documents:  []*PaletteDocumentResult{},
363			Beads:      []*PaletteBeadResult{},
364			Actions:    []*PaletteActionResult{},
365			Navigation: []*PaletteNavigationResult{},
366		}
367		if q == "" {
368			return out, nil
369		}
370	
371		matches := collectPaletteMatches(q, r.WorkingDir)
372		sort.SliceStable(matches, func(i, j int) bool {
373			if matches[i].score != matches[j].score {
374				return matches[i].score < matches[j].score
375			}
376			return matches[i].sortKey < matches[j].sortKey
377		})
378		if len(matches) > paletteResultCap {
379			matches = matches[:paletteResultCap]
380		}
381		for _, match := range matches {
382			switch match.kind {
383			case "document":
384				out.Documents = append(out.Documents, &PaletteDocumentResult{Kind: "document", Path: match.id, Title: match.title})
385			case "bead":
386				out.Beads = append(out.Beads, &PaletteBeadResult{Kind: "bead", ID: match.id, Title: match.title})
387			case "action":
388				out.Actions = append(out.Actions, &PaletteActionResult{Kind: "action", ID: match.id, Label: match.title})
389			case "nav":
390				out.Navigation = append(out.Navigation, &PaletteNavigationResult{Kind: "nav", Route: match.id, Title: match.title})
391			}
392		}
393		return out, nil
394	}
