422	func dispatchPluginAction(workingDir string, name string, action string) (string, error) {
423		state, err := registry.LoadState()
424		if err != nil {
425			return "", fmt.Errorf("loading plugin state: %w", err)
426		}
427	
428		switch action {
429		case "install":
430			if entry := state.FindInstalled(name); entry != nil && entry.VerifyFiles() {
431				return "installed", nil
432			}
433			entry, err := installRegistryPlugin(workingDir, state, name)
434			if err != nil {
435				return "", err
436			}
437			if entry != nil && entry.VerifyFiles() {
438				return "installed", nil
439			}
440			return "", fmt.Errorf("plugin %q install completed but recorded files are not present", name)
441		case "update":
442			installed := state.FindInstalled(name)
443			if installed == nil {
444				return "", fmt.Errorf("plugin %q is not installed", name)
445			}
446			pkg, err := registry.BuiltinRegistry().Find(name)
447			if err != nil {
448				return "", fmt.Errorf("plugin %q is not updateable from the built-in registry", name)
449			}
450			if installed.Version == pkg.Version && installed.VerifyFiles() {
451				return "installed", nil
452			}
453			entry, err := installRegistryPlugin(workingDir, state, name)
454			if err != nil {
455				return "", err
456			}
457			if entry != nil && entry.VerifyFiles() {
458				return "installed", nil
459			}
460			return "", fmt.Errorf("plugin %q update completed but recorded files are not present", name)
461		case "uninstall":
462			entry := state.FindInstalled(name)
463			if entry == nil {
464				return "", fmt.Errorf("plugin %q is not installed", name)
465			}
466			if err := registry.UninstallPackage(entry); err != nil {
467				return "", err
468			}
469			state.Remove(name)
470			if err := registry.SaveState(state); err != nil {
471				return "", fmt.Errorf("saving plugin state: %w", err)
472			}
473			return "uninstalled", nil
474		default:
475			return "", fmt.Errorf("unsupported plugin action %q", action)
476		}
477	}
478	
479	func installRegistryPlugin(workingDir string, state *registry.InstalledState, name string) (*registry.InstalledEntry, error) {
480		pkg, err := registry.BuiltinRegistry().Find(name)
481		if err != nil {
482			return nil, err
483		}
484	
485		origDir, _ := os.Getwd()
486		if workingDir != "" && origDir != workingDir {
487			if err := os.Chdir(workingDir); err != nil {
488				return nil, fmt.Errorf("entering project root: %w", err)
489			}
490			defer func() { _ = os.Chdir(origDir) }()
491		}
492	
493		entry, err := registry.InstallPackage(pkg)
494		if err != nil {
495			return nil, fmt.Errorf("installing plugin %q: %w", name, err)
496		}
497		state.AddOrUpdate(entry)
498		if err := registry.SaveState(state); err != nil {
499			return nil, fmt.Errorf("saving plugin state: %w", err)
500		}
501		return state.FindInstalled(name), nil
502	}
