553	func newDispatchID(prefix string, parts ...string) string {
554		segments := []string{slug(prefix)}
555		for _, part := range parts {
556			if s := slug(part); s != "" {
557				segments = append(segments, s)
558			}
559		}
560		segments = append(segments, randomHex(4))
561		return strings.Join(segments, "-")
562	}
563	
564	func randomHex(n int) string {
565		b := make([]byte, n)
566		if _, err := rand.Read(b); err != nil {
567			return time.Now().UTC().Format("20060102T150405.000000000")
568		}
569		return hex.EncodeToString(b)
570	}
