881	func buildSessionIndexEfficacySnapshot(entries []agent.SessionIndexEntry) efficacySnapshot {
882		grouped := map[string][]sessionEfficacyAttempt{}
883		for _, entry := range entries {
884			attempt := efficacyAttemptFromSession(entry)
885			if attempt.RowKey == "" {
886				continue
887			}
888			grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
889		}
890		rows := make([]*EfficacyRow, 0, len(grouped))
891		attemptDetails := map[string][]*EfficacyAttempt{}
892		for rowKey, group := range grouped {
893			sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
894			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
895			var inputTokens, outputTokens, durations []int
896			var costs []float64
897			var successes int
898			for _, attempt := range group {
899				if attempt.Outcome == "succeeded" {
900					successes++
901				}
902				inputTokens = append(inputTokens, attempt.InputTokens)
903				outputTokens = append(outputTokens, attempt.OutputTokens)
904				durations = append(durations, attempt.DurationMs)
905				if attempt.CostUsd != nil {
906					costs = append(costs, *attempt.CostUsd)
907				}
908				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
909					BeadID:            attempt.BeadID,
910					Outcome:           attempt.Outcome,
911					DurationMs:        attempt.DurationMs,
912					CostUsd:           attempt.CostUsd,
913					EvidenceBundleURL: attempt.EvidencePath,
914				})
915			}
916			parts := strings.Split(rowKey, "|")
917			row := &EfficacyRow{
918				RowKey:             rowKey,
919				Harness:            parts[0],
920				Provider:           parts[1],
921				Model:              parts[2],
922				Attempts:           len(group),
923				Successes:          successes,
924				SuccessRate:        float64(successes) / float64(len(group)),
925				MedianInputTokens:  medianInt(inputTokens),
926				MedianOutputTokens: medianInt(outputTokens),
927				MedianDurationMs:   medianInt(durations),
928				MedianCostUsd:      medianFloatPtr(costs),
929			}
930			if row.SuccessRate < efficacyWarningFloor {
931				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
932			}
933			rows = append(rows, row)
934		}
935		sort.Slice(rows, func(i, j int) bool {
936			if rows[i].SuccessRate != rows[j].SuccessRate {
937				return rows[i].SuccessRate > rows[j].SuccessRate
938			}
939			return rows[i].RowKey < rows[j].RowKey
940		})
941	
942		return efficacySnapshot{rows: rows, attempts: attemptDetails}
943	}
