1017		var out []paletteMatch
1018		if graph, err := docgraph.BuildGraphWithConfig(workingDir); err == nil {
1019			for _, doc := range graph.AllNodesForOutput() {
1020				if score, ok := paletteScore(query, doc.Path, doc.Title); ok {
1021					out = append(out, paletteMatch{
1022						kind:    "document",
1023						id:      filepath.ToSlash(doc.Path),
1024						title:   doc.Title,
1025						score:   score,
1026						sortKey: "document:" + doc.Path,
1027					})
1028				}
1029			}
1030		}
1031	
1032		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
1033		if beads, err := store.ReadAll(); err == nil {
1034			for _, b := range beads {
1035				if score, ok := paletteScore(query, b.ID, b.Title); ok {
1036					out = append(out, paletteMatch{kind: "bead", id: b.ID, title: b.Title, score: score, sortKey: "bead:" + b.ID})
1037				}
1038			}
1039		}
1040	
1041		for _, action := range []struct{ id, label string }{
