1044			{"run-checks", "Run checks"},
1045		} {
1046			if score, ok := paletteScore(query, action.id, action.label); ok {
1047				out = append(out, paletteMatch{kind: "action", id: action.id, title: action.label, score: score, sortKey: "action:" + action.id})
1048			}
1049		}
1050		for _, nav := range []struct{ route, title string }{
1051			{"/beads", "Beads"},
