1053			{"/graph", "Graph"},
1054			{"/workers", "Workers"},
1055			{"/personas", "Personas"},
1056			{"/plugins", "Plugins"},
1057			{"/efficacy", "Efficacy"},
1058		} {
1059			if score, ok := paletteScore(query, nav.route, nav.title); ok {
1060				out = append(out, paletteMatch{kind: "nav", id: nav.route, title: nav.title, score: score, sortKey: "nav:" + nav.route})
1061			}
