1066	func paletteScore(query string, fields ...string) (int, bool) {
1067		q := strings.ToLower(strings.TrimSpace(query))
1068		if q == "" {
1069			return 0, false
1070		}
1071		terms := strings.Fields(q)
1072		best := 1000
1073		for _, field := range fields {
1074			f := strings.ToLower(field)
1075			if strings.HasPrefix(f, q) {
1076				best = min(best, 0)
1077				continue
1078			}
1079			for _, part := range strings.FieldsFunc(f, func(r rune) bool {
1080				return r == '/' || r == '-' || r == '_' || r == '.' || r == ' ' || r == ':'
1081			}) {
1082				if strings.HasPrefix(part, q) {
1083					best = min(best, 1)
1084				}
1085			}
1086			allTerms := true
1087			for _, term := range terms {
1088				if !strings.Contains(f, term) {
1089					allTerms = false
1090					break
1091				}
1092			}
1093			if allTerms {
1094				best = min(best, 2)
1095			}
1096		}
1097		if best == 1000 {
1098			return 0, false
1099		}
1100		return best, true
1101	}
