371	func SessionIndexShardFiles(logDir string, q SessionIndexQuery) ([]string, error) {
372		dir := SessionIndexDir(logDir)
373		entries, err := os.ReadDir(dir)
374		if os.IsNotExist(err) {
375			return nil, nil
376		}
377		if err != nil {
378			return nil, err
379		}
380		var files []string
381		for _, ent := range entries {
382			if ent.IsDir() {
383				continue
384			}
385			name := ent.Name()
386			if !strings.HasPrefix(name, "sessions-") || !strings.HasSuffix(name, ".jsonl") {
387				continue
388			}
389			if !sessionShardIntersects(name, q) {
390				continue
391			}
392			files = append(files, filepath.Join(dir, name))
393		}
394		sort.Sort(sort.Reverse(sort.StringSlice(files)))
395		return files, nil
396	}
