515	func sessionIndexEntryInRange(entry SessionIndexEntry, q SessionIndexQuery) bool {
516		if q.StartedAfter != nil && entry.StartedAt.Before(*q.StartedAfter) {
517			return false
518		}
519		if q.StartedBefore != nil && !entry.StartedAt.Before(*q.StartedBefore) {
520			return false
521		}
522		return true
523	}
