525	func sessionShardIntersects(name string, q SessionIndexQuery) bool {
526		month, ok := sessionShardMonth(name)
527		if !ok {
528			return false
529		}
530		next := month.AddDate(0, 1, 0)
531		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
532			now := time.Now().UTC()
533			current := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
534			previous := current.AddDate(0, -1, 0)
535			return month.Equal(current) || month.Equal(previous)
536		}
537		if q.StartedAfter != nil && !next.After(*q.StartedAfter) {
538			return false
539		}
540		if q.StartedBefore != nil && !month.Before(*q.StartedBefore) {
541			return false
542		}
543		return true
544	}
