546	func sessionShardMonth(name string) (time.Time, bool) {
547		if len(name) != len("sessions-2006-01.jsonl") {
548			return time.Time{}, false
549		}
550		month, err := time.Parse("2006-01", strings.TrimSuffix(strings.TrimPrefix(name, "sessions-"), ".jsonl"))
551		if err != nil {
552			return time.Time{}, false
553		}
554		return month.UTC(), true
555	}
