605	func bodiesFromResultJSON(data []byte) (string, string) {
606		var raw map[string]any
607		if err := json.Unmarshal(data, &raw); err != nil {
608			return "", ""
609		}
610		response := firstString(raw, "response", "output", "final_text", "finalText", "detail")
611		stderr := firstString(raw, "stderr", "error")
612		return response, stderr
613	}
614	
615	func bodiesFromNativeLog(path string) (string, string) {
616		f, err := os.Open(path)
617		if err != nil {
618			return "", ""
619		}
620		defer f.Close()
621		var response, stderr string
622		scanner := bufio.NewScanner(f)
623		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
624		for scanner.Scan() {
625			var raw map[string]any
626			if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
627				continue
628			}
629			if s := firstNestedString(raw, []string{"data", "final_text"}, []string{"data", "finalText"}, []string{"final_text"}, []string{"finalText"}); s != "" {
630				response = s
631			}
632			if s := firstNestedString(raw, []string{"data", "error"}, []string{"error"}, []string{"stderr"}); s != "" {
633				stderr = s
634			}
635		}
636		return response, stderr
637	}
638	
639	func firstString(raw map[string]any, keys ...string) string {
640		for _, key := range keys {
641			if s, ok := raw[key].(string); ok && s != "" {
642				return s
643			}
644		}
645		return ""
646	}
647	
648	func firstNestedString(raw map[string]any, paths ...[]string) string {
649		for _, path := range paths {
650			cur := any(raw)
651			for _, key := range path {
652				m, ok := cur.(map[string]any)
653				if !ok {
654					cur = nil
655					break
656				}
657				cur = m[key]
658			}
659			if s, ok := cur.(string); ok && s != "" {
660				return s
661			}
662		}
663		return ""
664	}
