197		detail := buildProviderDetail(info, signal, outcomes, burnSummaries, now)
198		data, err := json.Marshal(detail)
199		if err != nil {
200			return mcpToolResult{Content: []mcpContent{{Type: "text", Text: "{}"}}}
201		}
202		return mcpToolResult{Content: []mcpContent{{Type: "text", Text: string(data)}}}
203	}
