205	// ---- Build helpers ----
206	
207	// signalFromHarnessInfo translates upstream HarnessInfo into the
208	// ddx-local RoutingSignalSnapshot shape used by buildProviderSummary /
209	// buildProviderDetail. This is the vocabulary translation shim introduced
210	// when the DDx-side provider-native parsers were retired (ddx-7bc0c8d5):
211	// upstream quota.Status values "ok|stale|unavailable" map to the existing
212	// "fresh|stale|unknown" vocabulary that the GraphQL/REST surface exposes so
213	// the SvelteKit frontend renders identically.
214	func signalFromHarnessInfo(info agentlib.HarnessInfo, now time.Time) agent.RoutingSignalSnapshot {
215		snap := agent.RoutingSignalSnapshot{Provider: info.Name}
216	
217		if info.Account != nil && (info.Account.Email != "" || info.Account.PlanType != "" || info.Account.OrgName != "") {
218			snap.Account = &agent.AccountInfo{
219				Email:    info.Account.Email,
220				PlanType: info.Account.PlanType,
221				OrgName:  info.Account.OrgName,
222			}
223		}
224	
225		if info.Quota == nil {
226			snap.CurrentQuota = agent.QuotaSignal{
227				Source: agent.SignalSourceMetadata{
228					Provider:  info.Name,
229					Kind:      "docs-only",
230					Freshness: "unknown",
231				},
232				State: "unknown",
233			}
234			snap.Source = snap.CurrentQuota.Source
235			return snap
236		}
237	
238		// Translate upstream quota.Status (ok|stale|unavailable|unauthenticated|unknown)
239		// into the existing ddx vocabulary.
240		state := "unknown"
241		switch info.Quota.Status {
242		case "ok":
243			state = "ok"
244		case "stale":
245			state = "ok" // stale-but-present data still counts as headroom.
246		case "unavailable", "unauthenticated":
247			state = "unknown"
248		}
249	
250		// Promote worst non-extra window to "blocked" if any window is blocked.
251		var usedPercent int
252		var windowMinutes int
253		var resetsAt string
254		var translatedWindows []agent.QuotaWindow
255		for _, w := range info.Quota.Windows {
256			qw := agent.QuotaWindow{
257				Name:          w.Name,
258				LimitID:       w.LimitID,
259				WindowMinutes: w.WindowMinutes,
260				UsedPercent:   w.UsedPercent,
261				ResetsAt:      w.ResetsAt,
262				ResetsAtUnix:  w.ResetsAtUnix,
263				State:         w.State,
264			}
265			translatedWindows = append(translatedWindows, qw)
266			if w.LimitID == "extra" {
267				continue
268			}
269			if w.State == "blocked" {
270				state = "blocked"
271				resetsAt = w.ResetsAt
272			}
273			if w.UsedPercent > float64(usedPercent) {
274				usedPercent = int(w.UsedPercent + 0.5)
275				windowMinutes = w.WindowMinutes
276			}
277		}
278		snap.QuotaWindows = translatedWindows
279	
280		freshness := "fresh"
281		if !info.Quota.Fresh {
282			freshness = "stale"
283		}
284		if info.Quota.Status == "unavailable" || info.Quota.Status == "unauthenticated" {
285			freshness = "unknown"
286		}
287	
288		kind := info.Quota.Source
289		if kind == "" {
290			kind = "stats-cache"
291		}
292	
293		var ageSeconds int64
294		if !info.Quota.CapturedAt.IsZero() {
295			if age := now.UTC().Sub(info.Quota.CapturedAt.UTC()); age > 0 {
296				ageSeconds = int64(age.Seconds())
297			}
298		}
299	
300		meta := agent.SignalSourceMetadata{
301			Provider:   info.Name,
302			Kind:       kind,
303			ObservedAt: info.Quota.CapturedAt.UTC(),
304			Freshness:  freshness,
305			AgeSeconds: ageSeconds,
306		}
307		snap.Source = meta
308		snap.CurrentQuota = agent.QuotaSignal{
309			Source:        meta,
310			State:         state,
311			UsedPercent:   usedPercent,
312			WindowMinutes: windowMinutes,
313			ResetsAt:      resetsAt,
314		}
315	
316		for _, u := range info.UsageWindows {
317			snap.HistoricalUsage.InputTokens += u.InputTokens
318			snap.HistoricalUsage.OutputTokens += u.OutputTokens
319			snap.HistoricalUsage.TotalTokens += u.TotalTokens
320		}
321		snap.HistoricalUsage.Source = meta
322	
323		return snap
324	}
