326	func buildProviderSummary(
327		info agentlib.HarnessInfo,
328		signal agent.RoutingSignalSnapshot,
329		outcomes []agent.RoutingOutcome,
330		now time.Time,
331	) ProviderSummary {
332		harnessOutcomes := filterProviderOutcomes(outcomes, info.Name, now, 7)
333		perf := computeProviderPerformance(harnessOutcomes)
334		sources := collectProviderSignalSources(signal, len(harnessOutcomes) > 0)
335	
336		var freshnessTS string
337		if ts := providerFreshnessTS(signal, harnessOutcomes); !ts.IsZero() {
338			freshnessTS = ts.UTC().Format(time.RFC3339)
339		}
340	
341		return ProviderSummary{
342			Harness:            info.Name,
343			DisplayName:        harnessDisplayName(info.Name),
344			Status:             providerStatusStrInfo(info),
345			AuthState:          providerAuthStateStr(signal),
346			QuotaHeadroom:      providerQuotaHeadroomStr(signal),
347			SignalSources:      sources,
348			FreshnessTS:        freshnessTS,
349			LastCheckedTS:      now.UTC().Format(time.RFC3339),
350			RecentSuccessRate:  perf.SuccessRate,
351			RecentLatencyP50MS: perf.P50LatencyMS,
352			CostClass:          harnessCosCostClassStr(info),
353		}
