356	func buildProviderDetail(
357		info agentlib.HarnessInfo,
358		signal agent.RoutingSignalSnapshot,
359		outcomes []agent.RoutingOutcome,
360		burnSummaries []agent.BurnSummary,
361		now time.Time,
362	) ProviderDetail {
363		outcomes7d := filterProviderOutcomes(outcomes, info.Name, now, 7)
364		outcomes30d := filterProviderOutcomes(outcomes, info.Name, now, 30)
365		perf := computeProviderPerformance(outcomes7d)
366		sources := collectProviderSignalSources(signal, len(outcomes7d) > 0)
