373		models := buildModelQuotaList(info, signal)
374		historicalUsage := computeProviderHistoricalUsage(info, signal, outcomes7d, outcomes30d)
375		burnEstimate := computeProviderBurnEstimate(info, burnSummaries, historicalUsage, signal)
