385			BurnEstimate:    burnEstimate,
386			RoutingSignals: ProviderRoutingSignals{
387				Availability: statusStr,
388				RequestFit:   providerRequestFitStrInfo(info),
389				CostEstimate: "unknown",
390				Performance:  perf,
391			},
392			SignalSources: sources,
