397	func buildModelQuotaList(info agentlib.HarnessInfo, signal agent.RoutingSignalSnapshot) []ProviderModelQuota {
398		models := harnessDefaultModels(info.Name)
399		if len(models) == 0 {
400			return []ProviderModelQuota{}
401		}
402	
403		quotaState := providerQuotaHeadroomStr(signal)
404		sourceEnum := signalSourceAPIEnum(signal.Source.Kind)
405		var sourceNote string
406		if quotaState == "unknown" && info.Name == "claude" {
407			sourceNote = "no stable non-PTY quota source confirmed"
408		}
409	
410		result := make([]ProviderModelQuota, 0, len(models))
411		for _, m := range models {
412			result = append(result, ProviderModelQuota{
413				Model:         m,
414				QuotaHeadroom: quotaState,
415				Source:        sourceEnum,
416				SourceNote:    sourceNote,
417			})
418		}
419		return result
420	}
