422	func computeProviderHistoricalUsage(
423		info agentlib.HarnessInfo,
424		signal agent.RoutingSignalSnapshot,
425		outcomes7d []agent.RoutingOutcome,
426		outcomes30d []agent.RoutingOutcome,
427	) *ProviderHistoricalUsage {
428		window7d := usageWindowFromSignalOrOutcomes(info, signal, outcomes7d)
429		window30d := usageWindowFromOutcomes(info, outcomes30d)
430		if window7d == nil && window30d == nil {
431			return nil
432		}
433		return &ProviderHistoricalUsage{
434			Window7D:  window7d,
435			Window30D: window30d,
436		}
437	}
