439	func usageWindowFromSignalOrOutcomes(
440		info agentlib.HarnessInfo,
441		signal agent.RoutingSignalSnapshot,
442		outcomes []agent.RoutingOutcome,
443	) *ProviderUsageWindow {
444		// Prefer provider-native signal if it has token data.
445		if signal.HistoricalUsage.TotalTokens > 0 || signal.HistoricalUsage.InputTokens > 0 {
446			w := &ProviderUsageWindow{
447				InputTokens:  signal.HistoricalUsage.InputTokens,
448				OutputTokens: signal.HistoricalUsage.OutputTokens,
449				TotalTokens:  signal.HistoricalUsage.TotalTokens,
450			}
451			if info.IsSubscription || info.IsLocal {
452				w.CostUSD = 0
453				if info.IsSubscription {
454					w.CostNote = "subscription plan; per-token cost not billed"
455				}
456			} else {
457				w.CostUSD = -1
458			}
459			return w
460		}
461		return usageWindowFromOutcomes(info, outcomes)
462	}
463	
464	func usageWindowFromOutcomes(info agentlib.HarnessInfo, outcomes []agent.RoutingOutcome) *ProviderUsageWindow {
465		if len(outcomes) == 0 {
466			return nil
467		}
468		var inTok, outTok int
469		var costUSD float64
470		hasCost := false
471		for _, o := range outcomes {
472			inTok += o.InputTokens
473			outTok += o.OutputTokens
474			if o.CostUSD > 0 {
475				costUSD += o.CostUSD
476				hasCost = true
477			}
478		}
479		if inTok == 0 && outTok == 0 {
480			return nil
481		}
482		w := &ProviderUsageWindow{
483			InputTokens:  inTok,
484			OutputTokens: outTok,
485			TotalTokens:  inTok + outTok,
486		}
487		if info.IsSubscription || info.IsLocal {
488			w.CostUSD = 0
489			if info.IsSubscription {
490				w.CostNote = "subscription plan; per-token cost not billed"
491			}
492		} else if hasCost {
493			w.CostUSD = costUSD
494		} else {
495			w.CostUSD = -1
496		}
497		return w
498	}
