500	func computeProviderBurnEstimate(
501		info agentlib.HarnessInfo,
502		burnSummaries []agent.BurnSummary,
503		usage *ProviderHistoricalUsage,
504		signal agent.RoutingSignalSnapshot,
505	) *ProviderBurnEstimate {
506		if !info.IsSubscription {
507			return nil
508		}
509	
510		// Find the most recent burn summary for this harness.
511		var latestBurn *agent.BurnSummary
512		for i := range burnSummaries {
513			if burnSummaries[i].Harness == info.Name {
514				if latestBurn == nil || burnSummaries[i].ObservedAt.After(latestBurn.ObservedAt) {
515					latestBurn = &burnSummaries[i]
516				}
517			}
518		}
519	
520		// Derive daily token rate from 7d window (DDx-observed or provider-native).
521		dailyTokenRate := -1.0
522		if usage != nil && usage.Window7D != nil && usage.Window7D.TotalTokens > 0 {
523			dailyTokenRate = float64(usage.Window7D.TotalTokens) / 7.0
524		}
525	
526		// Require at least one data source before emitting a burn estimate.
527		if latestBurn == nil && dailyTokenRate < 0 {
528			return nil
529		}
530	
531		// Determine source attribution.
532		sourceEnum := signalSourceAPIEnum(signal.Source.Kind)
533		var sourceStr string
534		if latestBurn != nil && dailyTokenRate >= 0 {
535			if sourceEnum != "none" {
536				sourceStr = sourceEnum + "+ddx-metrics"
537			} else {
538				sourceStr = "ddx-metrics"
539			}
540		} else if latestBurn != nil {
541			if sourceEnum != "none" {
542				sourceStr = sourceEnum
543			} else {
544				sourceStr = "ddx-metrics"
545			}
546		} else {
547			sourceStr = "ddx-metrics"
548		}
549	
550		subscriptionBurn := "unknown"
551		confidence := "low"
552		var freshnessTS string
553	
554		if latestBurn != nil {
555			switch {
556			case latestBurn.BurnIndex >= 0.8:
557				subscriptionBurn = "high"
558			case latestBurn.BurnIndex >= 0.5:
559				subscriptionBurn = "moderate"
560			case latestBurn.BurnIndex >= 0.1:
561				subscriptionBurn = "low"
562			}
563			switch {
564			case latestBurn.Confidence >= 0.8:
565				confidence = "high"
566			case latestBurn.Confidence >= 0.5:
567				confidence = "medium"
568			}
569			if !latestBurn.ObservedAt.IsZero() {
570				freshnessTS = latestBurn.ObservedAt.UTC().Format(time.RFC3339)
571			}
572		}
573	
574		return &ProviderBurnEstimate{
575			DailyTokenRate:   dailyTokenRate,
576			SubscriptionBurn: subscriptionBurn,
577			Source:           sourceStr,
578			Confidence:       confidence,
579			FreshnessTS:      freshnessTS,
580		}
581	}
