637	// filterProviderOutcomes returns outcomes for a given harness within the last windowDays days.
638	func filterProviderOutcomes(outcomes []agent.RoutingOutcome, harnessName string, now time.Time, windowDays int) []agent.RoutingOutcome {
639		cutoff := now.Add(-time.Duration(windowDays) * 24 * time.Hour)
640		result := make([]agent.RoutingOutcome, 0)
641		for _, o := range outcomes {
642			if o.Harness == harnessName && o.ObservedAt.After(cutoff) {
643				result = append(result, o)
644			}
645		}
646		return result
647	}
