649	// computeProviderPerformance computes latency percentiles and success rate from outcomes.
650	// Returns -1 sentinels when sample_count < 3 per FEAT-014.
651	func computeProviderPerformance(outcomes []agent.RoutingOutcome) ProviderPerformance {
652		perf := ProviderPerformance{
653			P50LatencyMS: -1,
654			P95LatencyMS: -1,
655			SuccessRate:  -1,
656			SampleCount:  len(outcomes),
657			Window:       "7d",
658		}
659		if len(outcomes) < 3 {
660			return perf
661		}
662		var successCount int
663		latencies := make([]int, 0, len(outcomes))
664		for _, o := range outcomes {
665			if o.Success {
666				successCount++
667			}
668			latencies = append(latencies, o.LatencyMS)
669		}
670		perf.SuccessRate = float64(successCount) / float64(len(outcomes))
671		sort.Ints(latencies)
672		perf.P50LatencyMS = latencies[len(latencies)/2]
673		p95Idx := int(float64(len(latencies)-1) * 0.95)
674		perf.P95LatencyMS = latencies[p95Idx]
675		return perf
676	}
