package agent

import (
	"strconv"
	"strings"
	"time"
)

// RateLimitSignal is a normalized rate-limit snapshot parsed from harness
// HTTP response headers. All fields are optional; an unset integer field is
// represented by -1 so callers can distinguish "unknown" from "zero".
type RateLimitSignal struct {
	CeilingTokens        int       // -1 when unknown
	CeilingWindowSeconds int       // -1 when unknown
	Remaining            int       // -1 when unknown
	ResetAt              time.Time // zero when unknown
}

// HasAny reports whether any field is populated.
func (s RateLimitSignal) HasAny() bool {
	if s.CeilingTokens >= 0 {
		return true
	}
	if s.CeilingWindowSeconds >= 0 {
		return true
	}
	if s.Remaining >= 0 {
		return true
	}
	if !s.ResetAt.IsZero() {
		return true
	}
	return false
}

// ParseRateLimitHeaders parses the common rate-limit headers emitted by
// subprocess harnesses that wrap provider HTTP calls. The harness name selects
// the header family. Headers not recognised by the mapping are ignored.
//
// Supported families:
//   - "claude": anthropic-ratelimit-tokens-{limit,remaining,reset} and
//     anthropic-ratelimit-requests-{limit,remaining,reset}. The tokens family
//     wins when both are present.
//   - "codex":  x-ratelimit-{limit,remaining,reset}-tokens (OpenAI/codex).
//
// Unknown harnesses return an empty signal.
func ParseRateLimitHeaders(harness string, headers map[string][]string) RateLimitSignal {
	h := normalizeHeaders(headers)
	sig := emptyRateLimitSignal()
	switch strings.ToLower(strings.TrimSpace(harness)) {
	case "claude", "anthropic":
		sig = parseClaudeRateLimit(h)
	case "codex", "openai":
		sig = parseCodexRateLimit(h)
	}
	return sig
}

func emptyRateLimitSignal() RateLimitSignal {
	return RateLimitSignal{
		CeilingTokens:        -1,
		CeilingWindowSeconds: -1,
		Remaining:            -1,
	}
}

// normalizeHeaders lowercases and flattens map[string][]string → map[string]string.
// The first value for each header wins.
func normalizeHeaders(headers map[string][]string) map[string]string {
	out := make(map[string]string, len(headers))
	for k, v := range headers {
		if len(v) == 0 {
			continue
		}
		out[strings.ToLower(strings.TrimSpace(k))] = strings.TrimSpace(v[0])
	}
	return out
}

// parseClaudeRateLimit reads the anthropic-ratelimit-* header family.
// Anthropic publishes separate windows for tokens and requests; tokens is the
// more useful signal for "will we run out soon", so we prefer it.
func parseClaudeRateLimit(h map[string]string) RateLimitSignal {
	sig := emptyRateLimitSignal()
	if limit, ok := parseIntHeader(h, "anthropic-ratelimit-tokens-limit"); ok {
		sig.CeilingTokens = limit
	}
	if rem, ok := parseIntHeader(h, "anthropic-ratelimit-tokens-remaining"); ok {
		sig.Remaining = rem
	}
	if resetStr, ok := h["anthropic-ratelimit-tokens-reset"]; ok {
		if t, ok2 := parseResetTimestamp(resetStr); ok2 {
			sig.ResetAt = t
		}
	}
	// If tokens family not populated, fall back to requests family for resetAt/window.
	if sig.CeilingTokens < 0 && sig.Remaining < 0 {
		if limit, ok := parseIntHeader(h, "anthropic-ratelimit-requests-limit"); ok {
			sig.CeilingTokens = limit
		}
		if rem, ok := parseIntHeader(h, "anthropic-ratelimit-requests-remaining"); ok {
			sig.Remaining = rem
		}
		if resetStr, ok := h["anthropic-ratelimit-requests-reset"]; ok {
			if t, ok2 := parseResetTimestamp(resetStr); ok2 {
				sig.ResetAt = t
			}
		}
	}
	if sig.HasAny() {
		// Anthropic rate-limit windows are published as 1-minute buckets for
		// token-level quotas. Record the window so clients can render "/ min".
		sig.CeilingWindowSeconds = 60
	}
	return sig
}

// parseCodexRateLimit reads the x-ratelimit-*-tokens header family.
func parseCodexRateLimit(h map[string]string) RateLimitSignal {
	sig := emptyRateLimitSignal()
	if limit, ok := parseIntHeader(h, "x-ratelimit-limit-tokens"); ok {
		sig.CeilingTokens = limit
	}
	if rem, ok := parseIntHeader(h, "x-ratelimit-remaining-tokens"); ok {
		sig.Remaining = rem
	}
	if resetStr, ok := h["x-ratelimit-reset-tokens"]; ok {
		if t, ok2 := parseResetTimestamp(resetStr); ok2 {
			sig.ResetAt = t
		}
	}
	if sig.HasAny() {
		sig.CeilingWindowSeconds = 60
	}
	return sig
}

func parseIntHeader(h map[string]string, key string) (int, bool) {
	v, ok := h[key]
	if !ok || v == "" {
		return 0, false
	}
	n, err := strconv.Atoi(v)
	if err != nil {
		return 0, false
	}
	return n, true
}

// parseResetTimestamp accepts either an absolute RFC3339 timestamp (Anthropic
// style) or a relative "30s" / "2m" / "1h" duration (codex style).
func parseResetTimestamp(s string) (time.Time, bool) {
	s = strings.TrimSpace(s)
	if s == "" {
		return time.Time{}, false
	}
	if t, err := time.Parse(time.RFC3339, s); err == nil {
		return t.UTC(), true
	}
	if d, err := time.ParseDuration(s); err == nil {
		return time.Now().UTC().Add(d), true
	}
	if secs, err := strconv.Atoi(s); err == nil {
		return time.Unix(int64(secs), 0).UTC(), true
	}
	return time.Time{}, false
}

package agent

import (
	"strings"
	"time"
)

// UsageWindowCounts is a rolling-window usage summary for one endpoint/harness,
// computed from SessionIndexEntry rows. A zero value indicates a window that
// was requested but contained no matching entries — callers decide whether to
// render "0" or "not reported".
type UsageWindowCounts struct {
	TokensLastHour  int
	TokensLast24h   int
	RequestsLastHour int
	RequestsLast24h  int
}

// UsageMatchKind selects which session field identifies the row.
type UsageMatchKind int

const (
	// MatchProvider matches SessionIndexEntry.Provider (endpoint providers).
	MatchProvider UsageMatchKind = iota
	// MatchHarness matches SessionIndexEntry.Harness (subprocess harnesses).
	MatchHarness
)

// AggregateUsageCounts walks a sorted-newest-first slice of SessionIndexEntry
// and returns rolling-window totals for the given name. Matching is
// case-insensitive; empty name returns a zero struct.
func AggregateUsageCounts(entries []SessionIndexEntry, name string, kind UsageMatchKind, now time.Time) UsageWindowCounts {
	name = strings.TrimSpace(strings.ToLower(name))
	if name == "" {
		return UsageWindowCounts{}
	}
	if now.IsZero() {
		now = time.Now().UTC()
	}
	var out UsageWindowCounts
	cutoffHour := now.Add(-time.Hour)
	cutoff24h := now.Add(-24 * time.Hour)
	for _, e := range entries {
		if !matchesUsageName(e, name, kind) {
			continue
		}
		if e.StartedAt.Before(cutoff24h) {
			continue
		}
		tokens := sessionTokens(e)
		out.TokensLast24h += tokens
		out.RequestsLast24h++
		if !e.StartedAt.Before(cutoffHour) {
			out.TokensLastHour += tokens
			out.RequestsLastHour++
		}
	}
	return out
}

func matchesUsageName(e SessionIndexEntry, lowerName string, kind UsageMatchKind) bool {
	switch kind {
	case MatchProvider:
		return strings.ToLower(strings.TrimSpace(e.Provider)) == lowerName
	case MatchHarness:
		return strings.ToLower(strings.TrimSpace(e.Harness)) == lowerName
	}
	return false
}

func sessionTokens(e SessionIndexEntry) int {
	if e.Tokens > 0 {
		return e.Tokens
	}
	return e.InputTokens + e.OutputTokens
}

// UsageBucket is one time-bucketed aggregate: tokens and request count.
type UsageBucket struct {
	Start    time.Time
	Tokens   int
	Requests int
}

// BucketUsage returns equally-spaced buckets covering the windowDays, aligned
// to `bucketSize`, in ascending order. Buckets with no sessions are emitted as
// zero counts so the series is dense for charts.
func BucketUsage(entries []SessionIndexEntry, name string, kind UsageMatchKind, now time.Time, windowDays int, bucketSize time.Duration) []UsageBucket {
	if windowDays <= 0 {
		return nil
	}
	if bucketSize <= 0 {
		bucketSize = time.Hour
	}
	name = strings.TrimSpace(strings.ToLower(name))
	if name == "" {
		return nil
	}
	if now.IsZero() {
		now = time.Now().UTC()
	}
	end := truncateToBucket(now, bucketSize).Add(bucketSize)
	start := end.Add(-time.Duration(windowDays) * 24 * time.Hour)
	bucketCount := int(end.Sub(start) / bucketSize)
	if bucketCount <= 0 {
		return nil
	}
	buckets := make([]UsageBucket, bucketCount)
	for i := range buckets {
		buckets[i].Start = start.Add(time.Duration(i) * bucketSize)
	}
	for _, e := range entries {
		if !matchesUsageName(e, name, kind) {
			continue
		}
		if e.StartedAt.Before(start) || !e.StartedAt.Before(end) {
			continue
		}
		idx := int(e.StartedAt.Sub(start) / bucketSize)
		if idx < 0 || idx >= bucketCount {
			continue
		}
		buckets[idx].Tokens += sessionTokens(e)
		buckets[idx].Requests++
	}
	return buckets
}

func truncateToBucket(t time.Time, d time.Duration) time.Time {
	t = t.UTC()
	if d <= 0 {
		return t
	}
	return t.Truncate(d)
}

// LinearSlope returns the least-squares slope (units per bucket) of a series
// of observations, or 0 when the series is too small to compute.
func LinearSlope(values []float64) float64 {
	n := len(values)
	if n < 2 {
		return 0
	}
	var sumX, sumY, sumXY, sumXX float64
	for i, y := range values {
		x := float64(i)
		sumX += x
		sumY += y
		sumXY += x * y
		sumXX += x * x
	}
	fn := float64(n)
	denom := fn*sumXX - sumX*sumX
	if denom == 0 {
		return 0
	}
	return (fn*sumXY - sumX*sumY) / denom
}

package graphql

import (
	"context"
	"fmt"
	"strings"
	"time"

	agentlib "github.com/DocumentDrivenDX/agent"
	"github.com/DocumentDrivenDX/ddx/internal/agent"
)

// ProviderStatuses is the resolver for the providerStatuses field.
// It mirrors the output of `ddx agent providers`, annotating each row with
// kind=ENDPOINT, a lastCheckedAt timestamp, and rolling usage derived from
// the sessions index. Quota is populated when the upstream ProviderInfo
// exposes token-level quota headers; null otherwise (FEAT-014 no-fabrication).
func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
	if err != nil {
		return []*ProviderStatus{}, nil //nolint:nilerr
	}
	providers, err := svc.ListProviders(ctx)
	if err != nil {
		return nil, fmt.Errorf("listing providers: %w", err)
	}

	now := time.Now().UTC()
	entries := r.sessionIndexEntries()
	lastChecked := now.Format(time.RFC3339)

	results := make([]*ProviderStatus, 0, len(providers))
	for _, p := range providers {
		url := p.BaseURL
		if url == "" {
			url = "(api)"
		}
		ps := &ProviderStatus{
			Name:              p.Name,
			Kind:              ProviderKindEndpoint,
			ProviderType:      p.Type,
			BaseURL:           url,
			Model:             p.DefaultModel,
			Status:            p.Status,
			ModelCount:        p.ModelCount,
			IsDefault:         p.IsDefault,
			LastCheckedAt:     strPtr(lastChecked),
			DefaultForProfile: defaultProfilesForEndpoint(p),
		}
		if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
			s := p.CooldownState.Until.UTC().Format(time.RFC3339)
			ps.CooldownUntil = &s
		}
		ps.Usage = buildUsage(entries, p.Name, agent.MatchProvider, now)
		ps.Quota = quotaFromProviderInfo(p)
		results = append(results, ps)
	}

	return results, nil
}

// HarnessStatuses is the resolver for the harnessStatuses field.
// It returns one row per subprocess harness (kind=HARNESS). Reachability is
// taken from HarnessInfo.Available, rolling usage from the sessions index,
// and quota from the harness-reported rate-limit data when available.
func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
	if err != nil {
		return []*ProviderStatus{}, nil //nolint:nilerr
	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return nil, fmt.Errorf("listing harnesses: %w", err)
	}

	now := time.Now().UTC()
	entries := r.sessionIndexEntries()
	lastChecked := now.Format(time.RFC3339)

	results := make([]*ProviderStatus, 0, len(infos))
	for _, info := range infos {
		ps := &ProviderStatus{
			Name:              info.Name,
			Kind:              ProviderKindHarness,
			ProviderType:      harnessTypeLabel(info),
			BaseURL:           "(subprocess)",
			Model:             info.DefaultModel,
			Status:            harnessStatusLine(info),
			ModelCount:        harnessModelCount(info),
			IsDefault:         false,
			LastCheckedAt:     strPtr(lastChecked),
			DefaultForProfile: []string{},
		}
		ps.Usage = buildUsage(entries, info.Name, agent.MatchHarness, now)
		ps.Quota = quotaFromHarnessInfo(info)
		results = append(results, ps)
	}

	return results, nil
}

// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
	svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
	if err != nil {
		return nil, nil //nolint:nilerr
	}
	dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
	if err != nil {
		return &DefaultRouteStatus{}, nil //nolint:nilerr
	}
	result := &DefaultRouteStatus{ModelRef: dec.Model}
	if dec.Provider != "" {
		p := dec.Provider
		result.ResolvedProvider = &p
	}
	if dec.Model != "" {
		m := dec.Model
		result.ResolvedModel = &m
	}
	return result, nil
}

// ProviderTrend is the resolver for the providerTrend field.
// It aggregates the sessions index into time buckets for one provider/harness
// and computes a projected-run-out-in-hours callout from the last-24h slope.
func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
	name = strings.TrimSpace(name)
	if name == "" {
		return nil, fmt.Errorf("name required")
	}
	if windowDays != 7 && windowDays != 30 {
		return nil, fmt.Errorf("windowDays must be 7 or 30")
	}
	now := time.Now().UTC()
	entries := r.sessionIndexEntries()

	kind, detected := detectProviderOrHarness(ctx, r, name)
	bucketKind := agent.MatchProvider
	if kind == ProviderKindHarness {
		bucketKind = agent.MatchHarness
	}

	bucketSize := time.Hour
	if windowDays > 7 {
		bucketSize = 4 * time.Hour
	}
	buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
	series := make([]*ProviderTrendPoint, 0, len(buckets))
	for _, b := range buckets {
		series = append(series, &ProviderTrendPoint{
			BucketStart: b.Start.UTC().Format(time.RFC3339),
			Tokens:      b.Tokens,
			Requests:    b.Requests,
		})
	}

	trend := &ProviderTrend{
		Name:       name,
		Kind:       kind,
		WindowDays: windowDays,
		Series:     series,
	}

	if detected != nil {
		if ceiling := detected.ceilingTokens; ceiling > 0 {
			c := ceiling
			trend.CeilingTokens = &c
			if p := projectRunOutHours(buckets, float64(ceiling)-float64(detected.remaining)); p > 0 {
				trend.ProjectedRunOutHours = &p
			}
		}
	}

	return trend, nil
}

// --------- helpers ---------

type detectedRow struct {
	ceilingTokens int
	remaining     int
}

// detectProviderOrHarness looks up a name against providers first, then
// harnesses, returning the resolved kind and quota signal (if any).
func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
	svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
	if err != nil {
		return ProviderKindEndpoint, nil
	}
	providers, _ := svc.ListProviders(ctx)
	for _, p := range providers {
		if strings.EqualFold(p.Name, name) {
			q := quotaFromProviderInfo(p)
			return ProviderKindEndpoint, detectedFromQuota(q)
		}
	}
	harnesses, _ := svc.ListHarnesses(ctx)
	for _, h := range harnesses {
		if strings.EqualFold(h.Name, name) {
			q := quotaFromHarnessInfo(h)
			return ProviderKindHarness, detectedFromQuota(q)
		}
	}
	return ProviderKindEndpoint, nil
}

func detectedFromQuota(q *ProviderQuota) *detectedRow {
	if q == nil {
		return nil
	}
	row := &detectedRow{ceilingTokens: -1, remaining: -1}
	if q.CeilingTokens != nil {
		row.ceilingTokens = *q.CeilingTokens
	}
	if q.Remaining != nil {
		row.remaining = *q.Remaining
	}
	return row
}

// projectRunOutHours returns the hours projected until `used` reaches ceiling
// based on the last-24-hour slope of the bucket series. Returns 0 when the
// slope is non-positive, the ceiling is already met, or the series is too
// short to estimate.
func projectRunOutHours(buckets []agent.UsageBucket, used float64) float64 {
	if len(buckets) < 2 {
		return 0
	}
	// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
	// buckets; 1h buckets gives 24.
	n := 24
	if n > len(buckets) {
		n = len(buckets)
	}
	tail := buckets[len(buckets)-n:]
	tokens := make([]float64, len(tail))
	for i, b := range tail {
		tokens[i] = float64(b.Tokens)
	}
	perBucket := agent.LinearSlope(tokens)
	// Convert slope-per-bucket to slope-per-hour.
	var bucketHours float64
	if len(tail) >= 2 {
		bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
	}
	if bucketHours <= 0 {
		bucketHours = 1
	}
	perHour := perBucket / bucketHours
	if perHour <= 0 {
		return 0
	}
	// Estimate remaining headroom as ceilingTokens - used. When `used` is
	// negative (ceiling unknown) we can't project.
	remaining := -used
	if remaining <= 0 {
		return 0
	}
	hours := remaining / perHour
	if hours <= 0 {
		return 0
	}
	return hours
}

// sessionIndexEntries reads the project's session index for all available
// shards. Errors are swallowed — a missing index is a normal "no data" state.
func (r *queryResolver) sessionIndexEntries() []agent.SessionIndexEntry {
	logDir := agent.SessionLogDirForWorkDir(r.WorkingDir)
	if logDir == "" {
		return nil
	}
	entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
	if err != nil {
		return nil
	}
	return entries
}

func buildUsage(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) *ProviderUsage {
	counts := agent.AggregateUsageCounts(entries, name, kind, now)
	u := &ProviderUsage{}
	v := counts.TokensLastHour
	u.TokensUsedLastHour = &v
	v2 := counts.TokensLast24h
	u.TokensUsedLast24h = &v2
	v3 := counts.RequestsLastHour
	u.RequestsLastHour = &v3
	v4 := counts.RequestsLast24h
	u.RequestsLast24h = &v4
	return u
}

// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
// Returns nil when no token-level ceiling is published.
func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
	if p.Quota == nil {
		return nil
	}
	return quotaFromState(p.Quota)
}

// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
// Returns nil when no token-level ceiling is published.
func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
	if info.Quota == nil {
		return nil
	}
	return quotaFromState(info.Quota)
}

func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
	if state == nil || len(state.Windows) == 0 {
		return nil
	}
	// Prefer a window with a concrete percentage and non-extra limit ID.
	var best *agentlib.QuotaState
	_ = best
	var pick *struct {
		CeilingTokens        int
		CeilingWindowSeconds int
		Remaining            int
		ResetAt              string
		Have                 bool
	}
	pick = &struct {
		CeilingTokens        int
		CeilingWindowSeconds int
		Remaining            int
		ResetAt              string
		Have                 bool
	}{CeilingTokens: -1, CeilingWindowSeconds: -1, Remaining: -1}
	for _, w := range state.Windows {
		if strings.EqualFold(w.LimitID, "extra") {
			continue
		}
		// The upstream QuotaWindow doesn't expose absolute token ceilings; we
		// surface the window length and reset time. Ceiling/remaining stay
		// unknown unless a harness-specific rate-limit-header path populates
		// them via QuotaProviderRateLimit (future work).
		if w.WindowMinutes > 0 {
			pick.CeilingWindowSeconds = w.WindowMinutes * 60
			pick.Have = true
		}
		if w.ResetsAt != "" {
			pick.ResetAt = w.ResetsAt
			pick.Have = true
		} else if w.ResetsAtUnix > 0 {
			pick.ResetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
			pick.Have = true
		}
		if pick.Have {
			break
		}
	}
	if !pick.Have {
		return nil
	}
	q := &ProviderQuota{}
	if pick.CeilingTokens >= 0 {
		v := pick.CeilingTokens
		q.CeilingTokens = &v
	}
	if pick.CeilingWindowSeconds >= 0 {
		v := pick.CeilingWindowSeconds
		q.CeilingWindowSeconds = &v
	}
	if pick.Remaining >= 0 {
		v := pick.Remaining
		q.Remaining = &v
	}
	if pick.ResetAt != "" {
		v := pick.ResetAt
		q.ResetAt = &v
	}
	return q
}

// QuotaFromRateLimitSignal produces a ProviderQuota from a parsed rate-limit
// header signal (see agent.ParseRateLimitHeaders). Exposed for future call
// sites where the server captures harness response headers.
func QuotaFromRateLimitSignal(sig agent.RateLimitSignal) *ProviderQuota {
	if !sig.HasAny() {
		return nil
	}
	q := &ProviderQuota{}
	if sig.CeilingTokens >= 0 {
		v := sig.CeilingTokens
		q.CeilingTokens = &v
	}
	if sig.CeilingWindowSeconds >= 0 {
		v := sig.CeilingWindowSeconds
		q.CeilingWindowSeconds = &v
	}
	if sig.Remaining >= 0 {
		v := sig.Remaining
		q.Remaining = &v
	}
	if !sig.ResetAt.IsZero() {
		v := sig.ResetAt.UTC().Format(time.RFC3339)
		q.ResetAt = &v
	}
	return q
}

// defaultProfilesForEndpoint returns the profile names where this endpoint is
// a default candidate. Current service surface exposes only a single
// IsDefault flag, so we return ["default"] when set, [] otherwise. The return
// shape supports multi-profile expansion without breaking callers.
func defaultProfilesForEndpoint(p agentlib.ProviderInfo) []string {
	if p.IsDefault {
		return []string{"default"}
	}
	return []string{}
}

