package agent

import (
	"testing"
	"time"
)

func TestParseRateLimitHeaders_ClaudeTokensFixture(t *testing.T) {
	// Captured from a real Anthropic 200 response body; only headers retained.
	headers := map[string][]string{
		"Anthropic-Ratelimit-Tokens-Limit":       {"80000"},
		"Anthropic-Ratelimit-Tokens-Remaining":   {"79200"},
		"Anthropic-Ratelimit-Tokens-Reset":       {"2026-04-23T05:00:00Z"},
		"Anthropic-Ratelimit-Requests-Limit":     {"50"},
		"Anthropic-Ratelimit-Requests-Remaining": {"49"},
	}
	sig := ParseRateLimitHeaders("claude", headers)
	if sig.CeilingTokens != 80000 {
		t.Fatalf("ceiling tokens: got %d want 80000", sig.CeilingTokens)
	}
	if sig.Remaining != 79200 {
		t.Fatalf("remaining: got %d want 79200", sig.Remaining)
	}
	if sig.CeilingWindowSeconds != 60 {
		t.Fatalf("window seconds: got %d want 60", sig.CeilingWindowSeconds)
	}
	if sig.ResetAt.IsZero() {
		t.Fatalf("reset at should be populated")
	}
	if got, want := sig.ResetAt.Format(time.RFC3339), "2026-04-23T05:00:00Z"; got != want {
		t.Fatalf("reset at: got %q want %q", got, want)
	}
}

func TestParseRateLimitHeaders_ClaudeFallsBackToRequestsFamily(t *testing.T) {
	headers := map[string][]string{
		"Anthropic-Ratelimit-Requests-Limit":     {"50"},
		"Anthropic-Ratelimit-Requests-Remaining": {"10"},
		"Anthropic-Ratelimit-Requests-Reset":     {"2026-04-23T05:00:00Z"},
	}
	sig := ParseRateLimitHeaders("claude", headers)
	if sig.CeilingTokens != 50 {
		t.Fatalf("ceiling (from requests family): got %d want 50", sig.CeilingTokens)
	}
	if sig.Remaining != 10 {
		t.Fatalf("remaining: got %d want 10", sig.Remaining)
	}
}

func TestParseRateLimitHeaders_CodexFixture(t *testing.T) {
	// Captured from an OpenAI codex response.
	headers := map[string][]string{
		"X-Ratelimit-Limit-Tokens":     {"200000"},
		"X-Ratelimit-Remaining-Tokens": {"194312"},
		"X-Ratelimit-Reset-Tokens":     {"30s"},
	}
	sig := ParseRateLimitHeaders("codex", headers)
	if sig.CeilingTokens != 200000 {
		t.Fatalf("ceiling: got %d want 200000", sig.CeilingTokens)
	}
	if sig.Remaining != 194312 {
		t.Fatalf("remaining: got %d want 194312", sig.Remaining)
	}
	if sig.CeilingWindowSeconds != 60 {
		t.Fatalf("window seconds: got %d want 60", sig.CeilingWindowSeconds)
	}
	if sig.ResetAt.IsZero() {
		t.Fatalf("expected relative reset to populate future timestamp")
	}
	if time.Until(sig.ResetAt) > 45*time.Second {
		t.Fatalf("reset-at is more than 45s in future, got %v", sig.ResetAt)
	}
}

func TestParseRateLimitHeaders_UnknownHarness(t *testing.T) {
	sig := ParseRateLimitHeaders("gemini", map[string][]string{
		"X-Ratelimit-Limit-Tokens": {"100"},
	})
	if sig.HasAny() {
		t.Fatalf("unknown harness should return empty signal, got %+v", sig)
	}
}

func TestParseRateLimitHeaders_MissingHeaders(t *testing.T) {
	sig := ParseRateLimitHeaders("claude", map[string][]string{})
	if sig.HasAny() {
		t.Fatalf("empty headers should return empty signal, got %+v", sig)
	}
}

func TestParseResetTimestamp_UnixSeconds(t *testing.T) {
	t0, ok := parseResetTimestamp("1800000000")
	if !ok {
		t.Fatal("expected unix seconds to parse")
	}
	if t0.Unix() != 1800000000 {
		t.Fatalf("unix: got %d", t0.Unix())
	}
}

func TestParseResetTimestamp_Invalid(t *testing.T) {
	_, ok := parseResetTimestamp("nonsense")
	if ok {
		t.Fatal("expected invalid to fail")
	}
}

package agent

import (
	"fmt"
	"testing"
	"time"
)

func fixedNow() time.Time {
	return time.Date(2026, 4, 23, 12, 0, 0, 0, time.UTC)
}

func makeEntry(started time.Time, provider, harness string, tokens int) SessionIndexEntry {
	return SessionIndexEntry{
		StartedAt: started,
		Provider:  provider,
		Harness:   harness,
		Tokens:    tokens,
	}
}

func TestAggregateUsageCounts_ProviderWindow(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeEntry(now.Add(-30*time.Minute), "qwen", "agent", 100),
		makeEntry(now.Add(-2*time.Hour), "qwen", "agent", 200),
		makeEntry(now.Add(-25*time.Hour), "qwen", "agent", 999), // outside 24h
		makeEntry(now.Add(-30*time.Minute), "other", "agent", 50),
	}
	c := AggregateUsageCounts(entries, "qwen", MatchProvider, now)
	if c.TokensLastHour != 100 {
		t.Errorf("tokens last hour: got %d want 100", c.TokensLastHour)
	}
	if c.TokensLast24h != 300 {
		t.Errorf("tokens last 24h: got %d want 300", c.TokensLast24h)
	}
	if c.RequestsLastHour != 1 {
		t.Errorf("requests last hour: got %d want 1", c.RequestsLastHour)
	}
	if c.RequestsLast24h != 2 {
		t.Errorf("requests last 24h: got %d want 2", c.RequestsLast24h)
	}
}

func TestAggregateUsageCounts_HarnessWindow(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeEntry(now.Add(-15*time.Minute), "", "claude", 500),
		makeEntry(now.Add(-5*time.Hour), "", "claude", 800),
		makeEntry(now.Add(-15*time.Minute), "", "codex", 100),
	}
	c := AggregateUsageCounts(entries, "claude", MatchHarness, now)
	if c.TokensLastHour != 500 || c.TokensLast24h != 1300 {
		t.Errorf("claude aggregate mismatch: %+v", c)
	}
}

func TestAggregateUsageCounts_FallBackToInputOutput(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		{StartedAt: now.Add(-30 * time.Minute), Harness: "claude", InputTokens: 400, OutputTokens: 100},
	}
	c := AggregateUsageCounts(entries, "claude", MatchHarness, now)
	if c.TokensLastHour != 500 {
		t.Errorf("fallback sum tokens: got %d want 500", c.TokensLastHour)
	}
}

func TestAggregateUsageCounts_CaseInsensitive(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		{StartedAt: now.Add(-1 * time.Minute), Harness: "CLAUDE", Tokens: 42},
	}
	c := AggregateUsageCounts(entries, "claude", MatchHarness, now)
	if c.TokensLastHour != 42 {
		t.Errorf("case-insensitive match: %+v", c)
	}
}

func TestBucketUsage_HourlyBuckets(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeEntry(now.Add(-30*time.Minute), "qwen", "", 100),
		makeEntry(now.Add(-90*time.Minute), "qwen", "", 50),
		makeEntry(now.Add(-30*time.Minute), "other", "", 10),
	}
	buckets := BucketUsage(entries, "qwen", MatchProvider, now, 1, time.Hour)
	if len(buckets) != 24 {
		t.Fatalf("expected 24 hourly buckets over 1 day, got %d", len(buckets))
	}
	var total int
	for _, b := range buckets {
		total += b.Tokens
	}
	if total != 150 {
		t.Errorf("total across buckets: got %d want 150", total)
	}
	// Ordering ascending
	for i := 1; i < len(buckets); i++ {
		if !buckets[i].Start.After(buckets[i-1].Start) {
			t.Errorf("buckets not ascending at %d", i)
		}
	}
}

func TestBucketUsage_4HourBuckets(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeEntry(now.Add(-1*time.Hour), "qwen", "", 10),
		makeEntry(now.Add(-5*time.Hour), "qwen", "", 20),
	}
	buckets := BucketUsage(entries, "qwen", MatchProvider, now, 2, 4*time.Hour)
	if len(buckets) != 12 {
		t.Fatalf("expected 12 4h buckets over 2 days, got %d", len(buckets))
	}
}

func TestLinearSlope(t *testing.T) {
	// Ascending series: slope should be positive.
	if s := LinearSlope([]float64{10, 20, 30, 40}); s != 10 {
		t.Errorf("perfect line slope: got %f want 10", s)
	}
	// Flat series: slope 0.
	if s := LinearSlope([]float64{5, 5, 5, 5}); s != 0 {
		t.Errorf("flat slope: got %f want 0", s)
	}
	// Too short.
	if s := LinearSlope([]float64{42}); s != 0 {
		t.Errorf("single point slope: got %f want 0", s)
	}
}

func TestAggregateUsageCounts_PerfOneThousandRows(t *testing.T) {
	// Per standing directive in ddx-9ce6842a: fixture of ≥1k session rows
	// covering last 24h; aggregation must return correct counts and stay
	// well under the 200ms HTTP budget.
	now := fixedNow()
	entries := make([]SessionIndexEntry, 0, 1000)
	for i := 0; i < 1000; i++ {
		minutes := time.Duration(i) * time.Minute
		entries = append(entries, SessionIndexEntry{
			StartedAt: now.Add(-minutes),
			Provider:  fmt.Sprintf("p%d", i%5),
			Harness:   fmt.Sprintf("h%d", i%5),
			Tokens:    10,
		})
	}
	start := time.Now()
	c := AggregateUsageCounts(entries, "p0", MatchProvider, now)
	elapsed := time.Since(start)
	// 200 sessions per provider per 1000/5 over ~17 hours → 60 in the last hour, 200 in last 24h.
	if c.RequestsLast24h != 200 {
		t.Errorf("expected 200 requests in 24h for p0, got %d", c.RequestsLast24h)
	}
	if c.TokensLast24h != 2000 {
		t.Errorf("expected 2000 tokens, got %d", c.TokensLast24h)
	}
	if elapsed > 50*time.Millisecond {
		t.Errorf("aggregation too slow on 1k fixture: %v (budget 50ms)", elapsed)
	}
}

