100				return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: base_url or host+port is required", index)
101			}
102			baseURL = fmt.Sprintf("http://%s:%d/v1", endpoint.Host, endpoint.Port)
103		}
104		if providerType == "" {
105			providerType = inferEndpointProviderType(baseURL, endpoint.Port)
106		}
107		if providerType == "" {
108			return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: type is required when it cannot be inferred", index)
109		}
110	
111		name := endpointProviderName(providerType, baseURL, endpoint, index)
112		return name, agentlib.ServiceProviderEntry{
113			Type:    providerType,
114			BaseURL: baseURL,
115			APIKey:  endpoint.APIKey,
116		}, nil
117	}
118	
119	func inferEndpointProviderType(baseURL string, port int) string {
120		low := strings.ToLower(baseURL)
121		switch {
122		case strings.Contains(low, "openrouter.ai"):
123			return "openrouter"
124		case strings.Contains(low, "openai.com"):
125			return "openai"
126		case strings.Contains(low, ":1235") || port == 1235:
127			return "omlx"
128		case strings.Contains(low, ":11434") || port == 11434:
129			return "ollama"
130		case strings.Contains(low, ":1234") || port == 1234:
131			return "lmstudio"
132		default:
133			return ""
134		}
135	}
136	
137	func endpointProviderName(providerType, baseURL string, endpoint ddxconfig.AgentEndpoint, index int) string {
138		host := endpoint.Host
139		port := endpoint.Port
140		if u, err := url.Parse(baseURL); err == nil {
141			if host == "" {
142				host = u.Hostname()
143			}
144			if port == 0 {
145				if p := u.Port(); p != "" {
146					if n, err := strconv.Atoi(p); err == nil {
147						port = n
148					}
149				}
150			}
151		}
152		parts := []string{providerType}
153		if host != "" {
154			parts = append(parts, host)
155		}
156		if port != 0 {
157			parts = append(parts, strconv.Itoa(port))
158		}
159		if len(parts) == 1 {
160			parts = append(parts, strconv.Itoa(index+1))
161		}
162		return sanitizeEndpointName(strings.Join(parts, "-"))
163	}
164	
165	func sanitizeEndpointName(s string) string {
166		s = strings.ToLower(strings.TrimSpace(s))
167		var b strings.Builder
168		lastDash := false
169		for _, r := range s {
170			keep := unicode.IsLetter(r) || unicode.IsDigit(r)
171			if keep {
172				b.WriteRune(r)
173				lastDash = false
174				continue
175			}
176			if !lastDash {
177				b.WriteByte('-')
178				lastDash = true
179			}
180		}
181		out := strings.Trim(b.String(), "-")
182		if out == "" {
183			return "endpoint"
184		}
185		return out
186	}
