188	func endpointHasLiveModels(ctx context.Context, baseURL, apiKey string) bool {
189		probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
190		defer cancel()
191	
192		req, err := http.NewRequestWithContext(probeCtx, http.MethodGet, strings.TrimRight(baseURL, "/")+"/models", nil)
193		if err != nil {
194			return false
195		}
196		if apiKey != "" {
197			req.Header.Set("Authorization", "Bearer "+apiKey)
198		}
199		resp, err := http.DefaultClient.Do(req)
200		if err != nil {
201			return false
202		}
203		defer resp.Body.Close() //nolint:errcheck
204		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
205			return false
206		}
207	
208		var payload struct {
209			Data []struct {
210				ID string `json:"id"`
211			} `json:"data"`
212		}
213		if err := json.NewDecoder(resp.Body).Decode(&payload); err != nil {
214			return false
215		}
216		for _, model := range payload.Data {
217			if strings.TrimSpace(model.ID) != "" {
218				return true
219			}
220		}
221		return false
222	}
